ordem_num = {n: i for i, n in enumerate(ordem, 1)}

for sh_name in wb.sheetnames:
    safe_name = sh_name.lower().replace(" ", "_").replace("ç", "c").replace("ã", "a").replace("ó", "o").replace("é", "e")
    prefix = f"{ordem_num.get(sh_name, 99):02d}_"
    csv_path = CSV_DIR / f"{prefix}{safe_name}.csv"
    sh = wb[sh_name]
    with open(csv_path, "w", encoding="utf-8-sig", newline="") as f:
        w = csv.writer(f, delimiter=";")
        for row in sh.iter_rows(values_only=True):
